---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';
import { getAlternateUrl, type Lang } from '../lib/navigation';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;

const alternateUrl = getAlternateUrl(Astro.url.pathname, lang as Lang);
const absoluteAlternateUrl = new URL(alternateUrl, Astro.site ?? 'https://ficcc.org').href;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} alternateUrl={absoluteAlternateUrl} />
    <link rel="preconnect" href="https://cdn.sanity.io" crossorigin />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <Header lang={lang} langToggleHref={alternateUrl} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
    <script>
      document.addEventListener('click', (e) => {
        const toggle = (e.target as HTMLElement).closest('.lang-toggle') as HTMLAnchorElement | null;
        if (toggle) {
          const targetLang = toggle.href.includes('/zh') ? 'zh' : 'en';
          document.cookie = 'lang-pref=' + targetLang + ';path=/;max-age=31536000;SameSite=Lax';
        }
      });
    </script>
  </body>
</html>

---
interface Props {
  title: string;
  body?: string;
  image?: string;
  href?: string;
}

const { title, body, image, href } = Astro.props;
const Tag = href ? 'a' : 'div';
---

<Tag class="card" {...(href ? { href } : {})}>
  {image && (
    <div class="card__image-wrap">
      <img class="card__image" src={image} alt="" loading="lazy" />
    </div>
  )}
  <div class="card__body">
    <h3 class="card__title">{title}</h3>
    {body && <p class="card__text">{body}</p>}
  </div>
</Tag>

<style>
  .card {
    display: flex;
    flex-direction: column;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    overflow: hidden;
    text-decoration: none;
    color: inherit;
    transition: box-shadow var(--transition), transform var(--transition);
  }

  a.card:hover {
    box-shadow: 0 4px 16px rgba(26, 26, 46, 0.1);
    transform: translateY(-2px);
  }

  a.card:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .card__image-wrap {
    aspect-ratio: 3 / 2;
    overflow: hidden;
  }

  .card__image {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .card__body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .card__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .card__text {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }
</style>

---
interface Props {
  title: string;
  date: string;
  time?: string;
  location?: string;
  image?: string;
  recurring?: boolean;
}

const { title, date, time, location, image, recurring } = Astro.props;

/** Format an ISO date string to a readable form, e.g. "Sunday, April 12, 2026" */
function formatDate(iso: string): string {
  try {
    const d = new Date(iso);
    return d.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  } catch {
    return iso;
  }
}

const displayDate = formatDate(date);
---

<div class="event-card">
  {image && (
    <div class="event-card__image-wrap">
      <img class="event-card__image" src={image} alt="" loading="lazy" />
    </div>
  )}
  <div class="event-card__body">
    <div class="event-card__header">
      <h3 class="event-card__title">{title}</h3>
      {recurring && <span class="event-card__badge">Recurring</span>}
    </div>
    <p class="event-card__date">{displayDate}</p>
    {time && <p class="event-card__meta">{time}</p>}
    {location && <p class="event-card__meta">{location}</p>}
  </div>
</div>

<style>
  .event-card {
    display: flex;
    flex-direction: column;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    overflow: hidden;
  }

  .event-card__image-wrap {
    aspect-ratio: 3 / 2;
    overflow: hidden;
  }

  .event-card__image {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .event-card__body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .event-card__header {
    display: flex;
    align-items: baseline;
    gap: var(--space-3);
    flex-wrap: wrap;
  }

  .event-card__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .event-card__badge {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-xs, 0.75rem);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    padding: 0.125rem var(--space-2);
    border-radius: var(--radius-sm, 0.25rem);
    white-space: nowrap;
    line-height: 1.4;
  }

  .event-card__date {
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-terracotta);
    line-height: var(--leading-relaxed);
  }

  .event-card__meta {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
    line-height: var(--leading-relaxed);
  }
</style>

